import { Marker, Popup } from "react-leaflet";
import L from "leaflet";

export default function PlaneMarker({ position, flightData }) {
  if (!position || isNaN(position[0]) || isNaN(position[1])) return null;
  if (!flightData) return null;

  // ✨ Use heading if available, fallback to 0
  const rotation = flightData.heading || 0;

  const icon = L.divIcon({
    html: `<img 
      src="https://cdn-icons-png.flaticon.com/512/34/34627.png"
      style="
        width:32px;
        transform: rotate(${rotation}deg);
        transition: transform 0.5s linear;
      " 
    />`,
    className: "",
  });

  return (
    <Marker position={position} icon={icon}>
      <Popup>
        ✈️ {flightData.callsign}<br />
        Alt: {Math.round(flightData.altitude)} m<br />
        Speed: {Math.round(flightData.velocity)} m/s
      </Popup>
    </Marker>
  );
}
